<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#CDD6F4;"> Model</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">SPEED  </span><span style="color:#6C7086;font-style:italic;"># Gemini Flash, Haiku, etc.</span></span>
