<span class="line"><span style="color:#CBA6F7;">        return</span><span style="color:#EBA0AC;font-style:italic;"> model_strengths</span><span style="color:#9399B2;">[</span><span style="color:#EBA0AC;font-style:italic;">task</span><span style="color:#9399B2;">.</span><span style="color:#EBA0AC;font-style:italic;">language</span><span style="color:#9399B2;">]</span></span>
